var query = $.input.jobQuery + ' job listing hiring';
if ($.input.location) query += ' ' + $.input.location;
return { query: query };

var results = $.steps.searchJobs.response.results || [];
var listingsText = '';
results.forEach(function(r, i) {
  listingsText += 'LISTING ' + (i + 1) + ':\n';
  listingsText += 'Title: ' + (r.title || '') + '\n';
  listingsText += 'URL: ' + (r.url || '') + '\n';
  listingsText += 'Date: ' + (r.publishedDate || '') + '\n';
  listingsText += 'Content:\n' + (r.text || '').slice(0, 1500) + '\n\n';
});
return { listingsText: listingsText, listingCount: results.length };

var data = $.steps.compileListings.output;
var prompt = 'You are a job search analyst. Parse and score the following job listings against the candidate's preferences.

';
prompt += 'SEARCH QUERY: ' + $.input.jobQuery + '
';
if ($.input.location) prompt += 'PREFERRED LOCATION: ' + $.input.location + '
';
if ($.input.salaryRange) prompt += 'TARGET SALARY: ' + $.input.salaryRange + '
';
if ($.input.mustHaveSkills) prompt += 'REQUIRED SKILLS: ' + $.input.mustHaveSkills + '
';
prompt += '
JOB LISTINGS (' + data.listingCount + '):
' + data.listingsText + '
';
prompt += 'INSTRUCTIONS:
';
prompt += '- Parse each listing into structured data
';
prompt += '- Score each job 1-100 on fit with candidate preferences
';
prompt += '- Extract: company, title, location, salary (if mentioned), skills required
';
prompt += '- Flag remote-friendly positions
';
prompt += '- Rank from best to worst fit

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "jobs": [
';
prompt += '    {
';
prompt += '      "rank": 1,
';
prompt += '      "company": "...",
';
prompt += '      "title": "...",
';
prompt += '      "location": "...",
';
prompt += '      "salary": "...",
';
prompt += '      "remote": true,
';
prompt += '      "skillsRequired": ["skill1"],
';
prompt += '      "skillsMatch": "High|Medium|Low",
';
prompt += '      "fitScore": 85,
';
prompt += '      "url": "...",
';
prompt += '      "highlights": "Why this job stands out",
';
prompt += '      "concerns": "Any potential issues"
';
prompt += '    }
';
prompt += '  ],
';
prompt += '  "totalJobs": 0,
';
prompt += '  "topRecommendation": "Brief recommendation"
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiAnalyze.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { jobs: [], totalJobs: 0, topRecommendation: raw }; }

var ai = $.steps.parseAI.output;
var jobs = ai.jobs || [];
var date = new Date().toISOString().split('T')[0];
var sheetData = jobs.map(function(j) {
  return {
    'Rank': j.rank || '',
    'Company': j.company || '',
    'Job Title': j.title || '',
    'Location': j.location || '',
    'Salary': j.salary || '',
    'Remote': j.remote ? 'Yes' : 'No',
    'Skills Match': j.skillsMatch || '',
    'Fit Score': j.fitScore || '',
    'Skills Required': (j.skillsRequired || []).join(', '),
    'Highlights': (j.highlights || '').slice(0, 200),
    'Concerns': (j.concerns || '').slice(0, 200),
    'URL': j.url || '',
    'Date Found': date
  };
});
return { sheetData: sheetData, jobCount: jobs.length, date: date };
